```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ─── DataRow: CalculateTotal ───────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0,  10.00,  DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0,  50.00,  DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00,  DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62,  DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00,  5, 0.10, 0.00,   DisplayName = "Zero price")]
    [DataRow(10.00, 0, 0.10, 0.00,   DisplayName = "Zero quantity")]
    public void CalculateTotal_ValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative price throws")]
    public void CalculateTotal_NegativePrice_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity throws")]
    public void CalculateTotal_NegativeQuantity_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // ─── DynamicData: ApplyDiscount ────────────────────────────────────

    [TestMethod]
    [DynamicData(nameof(DiscountTestCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_ValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<object[]> DiscountTestCases()
    {
        yield return new object[] { 100m, 0m,   100m };    // No discount
        yield return new object[] { 100m, 10m,  90m };     // 10% off
        yield return new object[] { 100m, 50m,  50m };     // Half off
        yield return new object[] { 100m, 100m, 0m };      // Free
        yield return new object[] { 49.99m, 25m, 37.4925m }; // Fractional
    }

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_InvalidPercent_Throws(
        decimal price, decimal discountPercent)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));
    }

    public static IEnumerable<object[]> InvalidDiscountCases()
    {
        yield return new object[] { 100m, -1m };   // Below range
        yield return new object[] { 100m, 101m };  // Above range
    }
}
```

**Key modern MSTest practices shown:**

| Practice | Detail |
|----------|--------|
| `[DataRow]` | Best for compile-time constants; uses `double` since `decimal` isn't a valid attribute arg—cast in the method body |
| `[DynamicData]` | Best when you need `decimal` precision or complex objects; uses a static method returning `IEnumerable<object[]>` |
| `DisplayName` | Makes Test Explorer output readable |
| Separate test methods for exceptions | Keeps happy-path tests distinct from validation tests |
| `sealed` test class | Avoids unintended inheritance (MSTest 3.x best practice) |
| `[TestInitialize]` | Keeps each test isolated with a fresh instance |

> **Note:** `DataRow` can't accept `decimal` literals directly (they aren't valid attribute arguments in C#), so the pattern is to pass `double` and cast to `decimal` in the method body.
